#include <stdio.h>
#include <stdlib.h>
#include <omp.h>

#ifdef RD_WG_SIZE_0_0
        #define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
        #define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
        #define BLOCK_SIZE RD_WG_SIZE
#else
        #define BLOCK_SIZE 16
#endif

void lud_diagonal_omp(float *m, int matrix_dim, int offset)
{
  int i, j, x;
  float shadow[BLOCK_SIZE][BLOCK_SIZE];

  int array_offset = offset * matrix_dim + offset;
  for (i = 0; i < BLOCK_SIZE; i++) {
    for (x = 0; x < BLOCK_SIZE; x++) {
      shadow[i][x] = m[array_offset + x];
    }
    array_offset += matrix_dim;
  }

  for (i = 0; i < BLOCK_SIZE - 1; i++) {
    for (x = i + 1; x < BLOCK_SIZE; x++) {
      for (j = 0; j < i; j++)
        shadow[x][i] -= shadow[x][j] * shadow[j][i];
      shadow[x][i] /= shadow[i][i];
    }

    for (x = 0; x < BLOCK_SIZE; x++) {
      for (j = 0; j < i + 1; j++)
        shadow[i + 1][x] -= shadow[i + 1][j] * shadow[j][x];
    }
  }

  array_offset = (offset + 1) * matrix_dim + offset;
  for (i = 1; i < BLOCK_SIZE; i++) {
    for (x = 0; x < BLOCK_SIZE; x++) {
      m[array_offset + x] = shadow[i][x];
    }
    array_offset += matrix_dim;
  }
}

void lud_perimeter_block_omp(float *m, int matrix_dim, int offset, int block_idx)
{
  float dia[BLOCK_SIZE][BLOCK_SIZE];
  float peri_row[BLOCK_SIZE][BLOCK_SIZE];
  float peri_col[BLOCK_SIZE][BLOCK_SIZE];
  int i, j, array_offset, idx;

  array_offset = offset * matrix_dim + offset;
  for (i = 0; i < BLOCK_SIZE / 2; i++) {
    for (idx = 0; idx < BLOCK_SIZE; idx++) {
      dia[i][idx] = m[array_offset + idx];
    }
    array_offset += matrix_dim;
  }

  array_offset = (offset + BLOCK_SIZE / 2) * matrix_dim + offset;
  for (i = BLOCK_SIZE / 2; i < BLOCK_SIZE; i++) {
    for (idx = 0; idx < BLOCK_SIZE; idx++) {
      dia[i][idx] = m[array_offset + idx];
    }
    array_offset += matrix_dim;
  }

  array_offset = offset * matrix_dim + offset;
  for (i = 0; i < BLOCK_SIZE; i++) {
    for (idx = 0; idx < BLOCK_SIZE; idx++) {
      peri_row[i][idx] = m[array_offset + (block_idx + 1) * BLOCK_SIZE + idx];
    }
    array_offset += matrix_dim;
  }

  array_offset = (offset + (block_idx + 1) * BLOCK_SIZE) * matrix_dim + offset;
  for (i = 0; i < BLOCK_SIZE; i++) {
    for (idx = 0; idx < BLOCK_SIZE; idx++) {
      peri_col[i][idx] = m[array_offset + idx];
    }
    array_offset += matrix_dim;
  }

  for (i = 1; i < BLOCK_SIZE; i++) {
    for (idx = 0; idx < BLOCK_SIZE; idx++) {
      for (j = 0; j < i; j++)
        peri_row[i][idx] -= dia[i][j] * peri_row[j][idx];
    }
  }

  for (i = 0; i < BLOCK_SIZE; i++) {
    for (idx = 0; idx < BLOCK_SIZE; idx++) {
      for (j = 0; j < i; j++)
        peri_col[idx][i] -= peri_col[idx][j] * dia[j][i];
      peri_col[idx][i] /= dia[i][i];
    }
  }

  array_offset = (offset + 1) * matrix_dim + offset;
  for (i = 1; i < BLOCK_SIZE; i++) {
    for (idx = 0; idx < BLOCK_SIZE; idx++) {
      m[array_offset + (block_idx + 1) * BLOCK_SIZE + idx] = peri_row[i][idx];
    }
    array_offset += matrix_dim;
  }

  array_offset = (offset + (block_idx + 1) * BLOCK_SIZE) * matrix_dim + offset;
  for (i = 0; i < BLOCK_SIZE; i++) {
    for (idx = 0; idx < BLOCK_SIZE; idx++) {
      m[array_offset + idx] = peri_col[i][idx];
    }
    array_offset += matrix_dim;
  }
}

void lud_perimeter_omp(float *m, int matrix_dim, int offset)
{
  int num_blocks = (matrix_dim - offset) / BLOCK_SIZE - 1;
  int block_idx;

  for (block_idx = 0; block_idx < num_blocks; block_idx++) {
    lud_perimeter_block_omp(m, matrix_dim, offset, block_idx);
  }
}

void lud_internal_block_omp(float *m, int matrix_dim, int offset, int block_x, int block_y)
{
  float peri_row[BLOCK_SIZE][BLOCK_SIZE];
  float peri_col[BLOCK_SIZE][BLOCK_SIZE];
  int i, global_row_id, global_col_id;
  float sum;
  int tid_x, tid_y;

  global_row_id = offset + (block_y + 1) * BLOCK_SIZE;
  global_col_id = offset + (block_x + 1) * BLOCK_SIZE;

  for (tid_y = 0; tid_y < BLOCK_SIZE; tid_y++) {
    for (tid_x = 0; tid_x < BLOCK_SIZE; tid_x++) {
      peri_row[tid_y][tid_x] = m[(offset + tid_y) * matrix_dim + global_col_id + tid_x];
      peri_col[tid_y][tid_x] = m[(global_row_id + tid_y) * matrix_dim + offset + tid_x];
    }
  }

  for (tid_y = 0; tid_y < BLOCK_SIZE; tid_y++) {
    for (tid_x = 0; tid_x < BLOCK_SIZE; tid_x++) {
      sum = 0;
      for (i = 0; i < BLOCK_SIZE; i++)
        sum += peri_col[tid_y][i] * peri_row[i][tid_x];
      m[(global_row_id + tid_y) * matrix_dim + global_col_id + tid_x] -= sum;
    }
  }
}

void lud_internal_omp(float *m, int matrix_dim, int offset)
{
  int num_blocks = (matrix_dim - offset) / BLOCK_SIZE - 1;
  int block_x, block_y;

  for (block_y = 0; block_y < num_blocks; block_y++) {
    for (block_x = 0; block_x < num_blocks; block_x++) {
      lud_internal_block_omp(m, matrix_dim, offset, block_x, block_y);
    }
  }
}

void lud_omp(float *m, int matrix_dim)
{
  int i;

  for (i = 0; i < matrix_dim - BLOCK_SIZE; i += BLOCK_SIZE) {
    lud_diagonal_omp(m, matrix_dim, i);
    lud_perimeter_omp(m, matrix_dim, i);
    lud_internal_omp(m, matrix_dim, i);
  }
  lud_diagonal_omp(m, matrix_dim, i);
}
